108	type countingReadCloser struct {
109		io.ReadCloser
110	
111		n       int64
112		onClose func(int64)
113	}
114	
115	func (c *countingReadCloser) Read(p []byte) (int, error) {
116		n, err := c.ReadCloser.Read(p)
117		c.n += int64(n)
118		return n, err //nolint:wrapcheck // Read must preserve io.EOF for io.Reader contract
119	}
120	
121	func (c *countingReadCloser) Close() error {
122		err := c.ReadCloser.Close()
123		if c.onClose != nil {
124			c.onClose(c.n)
125			c.onClose = nil
126		}
127		if err != nil {
128			return fmt.Errorf("close: %w", err)
129		}
130		return nil
131	}
