397	// newSession performs the shared setup: protocol validation, mapping validation,
398	// connection creation, and ref discovery.
399	func newSession(ctx context.Context, cfg Config, needTarget bool) (*syncSession, error) {
400		mode, err := validation.NormalizeProtocolMode(cfg.ProtocolMode)
401		if err != nil {
402			return nil, fmt.Errorf("normalize protocol mode: %w", err)
403		}
404		cfg.ProtocolMode = mode
405		switch cfg.Mode {
406		case "", modeSync:
407			cfg.Mode = modeSync
408		case modeReplicate:
409		default:
410			return nil, fmt.Errorf("unsupported operation mode %q", cfg.Mode)
411		}
412		if _, err := validation.ValidateMappings(cfg.Mappings); err != nil {
413			return nil, fmt.Errorf("validate mappings: %w", err)
414		}
415		if cfg.Mode == modeReplicate && cfg.Force {
416			return nil, errors.New("replicate does not support --force; use sync instead")
417		}
418		if needTarget {
419			if err := validation.ValidateEndpoints(cfg.Source.URL, cfg.Target.URL); err != nil {
420				return nil, fmt.Errorf("validate endpoints: %w", err)
421			}
422		}
423	
424		s := &syncSession{
425			cfg:             cfg,
426			stats:           newStats(cfg.ShowStats),
427			measurementDone: startMeasurement(cfg.MeasureMemory),
428		}
429		if cfg.Verbose {
430			s.logger = slog.New(slog.NewTextHandler(os.Stderr, &slog.HandlerOptions{
431				Level: slog.LevelInfo,
432			}))
433		}
434	
435		s.sourceConn, err = newConn(cfg.Source, "source", s.stats, cfg.HTTPClient)
436		if err != nil {
437			return nil, fmt.Errorf("create source transport: %w", err)
438		}
439	
440		refPrefixes := planner.RefPrefixes(cfg.Mappings, cfg.IncludeTags)
441		sourceRefs, sourceService, err := gitproto.ListSourceRefs(ctx, s.sourceConn, cfg.ProtocolMode, refPrefixes)
442		if err != nil {
443			return nil, fmt.Errorf("list source refs: %w", err)
444		}
445		sourceService.Verbose = cfg.Verbose
446		s.sourceService = sourceService
447		s.sourceRefMap = gitproto.RefHashMap(sourceRefs)
448	
449		if needTarget {
450			targetConn, err := newConn(cfg.Target, "target", s.stats, cfg.HTTPClient)
451			if err != nil {
452				return nil, fmt.Errorf("create target transport: %w", err)
453			}
454			targetAdv, err := gitproto.AdvertisedRefsV1(ctx, targetConn, transport.ReceivePackService)
455			if err != nil {
456				return nil, fmt.Errorf("list target refs: %w", err)
457			}
458			targetRefSlice, err := gitproto.AdvRefsToSlice(targetAdv)
459			if err != nil {
460				return nil, fmt.Errorf("decode target refs: %w", err)
461			}
462			targetRefMap := gitproto.RefHashMap(targetRefSlice)
463			targetFeatures := gitproto.TargetFeaturesFromAdvRefs(targetAdv)
464			s.target = &targetSession{
465				conn:     targetConn,
466				adv:      targetAdv,
467				refMap:   targetRefMap,
468				features: targetFeatures,
469				policy: planner.RelayTargetPolicy{
470					CapabilitiesKnown: targetFeatures.Known,
471					NoThin:            targetFeatures.NoThin,
472				},
473				pusher: gitproto.NewPusher(targetConn, targetAdv, cfg.Verbose),
474			}
475		}
476	
477		return s, nil
478	}
