339	// needsLocalSourceClosure reports whether the sync must populate the
340	// in-memory store with the full source closure before running. The fetch
341	// is required when:
342	//   - Force or prune is set: incremental relay is disabled, so the
343	//     materialized fallback will run and needs the closure.
344	//   - Any desired ref already exists on target at a different hash: a
345	//     branch fast-forward check will need ancestry data, or a tag retarget
346	//     will route to materialized.
347	//
348	// When all desired refs are either skips (target hash matches source) or
349	// creates (target hash is zero), incremental relay handles the push without
350	// the closure — the upfront fetch would just be wasted bandwidth, since
351	// relay does its own FetchPack on the source.
352	func needsLocalSourceClosure(
353		cfg Config,
354		desired map[plumbing.ReferenceName]planner.DesiredRef,
355		targetRefs map[plumbing.ReferenceName]plumbing.Hash,
356	) bool {
357		if cfg.Force || cfg.Prune {
358			return true
359		}
360		for targetRef, want := range desired {
361			targetHash := targetRefs[targetRef]
362			if targetHash.IsZero() {
363				continue
364			}
365			if targetHash == want.SourceHash {
366				continue
367			}
368			return true
369		}
370		return false
371	}
