113	func (s *statsCollector) liveSides() []SideBytes {
114		s.sidesMu.RLock()
115		defer s.sidesMu.RUnlock()
116		out := make([]SideBytes, 0, len(s.sides))
117		for label, sc := range s.sides {
118			out = append(out, SideBytes{Label: label, Bytes: sc.bytes.Load()})
119		}
120		return out
121	}
