199		}
200		return n, err //nolint:wrapcheck // Read must preserve io.EOF for io.Reader contract
201	}
202	
203	func (c *countingReadCloser) Close() error {
204		err := c.ReadCloser.Close()
205		if c.onClose != nil {
206			c.onClose(c.n)
207			c.onClose = nil
208		}
209		if err != nil {
210			return fmt.Errorf("close: %w", err)
211		}
