	t.Parallel()
	stats := newStats(true)
	stats.side("source").bytes.Store(2 * 1024 * 1024)
	stats.side("target").bytes.Store(1024 * 1024)

	var buf bytes.Buffer
	p := newProgressReporter(&buf, stats, 0)
	p.render(true)

