	t.Parallel()
	stats := Stats{
		Enabled:      true,
		Items:        map[string]*ServiceStats{},
		ElapsedNanos: time.Second.Nanoseconds(),
		Sides: []SideBytes{
			{Label: "target", Bytes: 1 << 20},
			{Label: "source", Bytes: 4 << 20},
