253	// prefixedLineWriter prepends a fixed prefix to each line of input written
254	// to the wrapped writer. Git sideband progress arrives as chunks that may
255	// contain '\n' between full lines or '\r' for in-place updates ("Resolving
256	// deltas:  12%\r"); both are treated as line terminators so the next chunk
257	// gets a fresh prefix.
258	type prefixedLineWriter struct {
259		w           io.Writer
260		prefix      string
261		atLineStart bool
262	}
263	
264	func (p *prefixedLineWriter) Write(b []byte) (int, error) {
265		consumed := 0
266		for len(b) > 0 {
267			if p.atLineStart {
268				if _, err := io.WriteString(p.w, p.prefix); err != nil {
269					return consumed, fmt.Errorf("write prefix: %w", err)
270				}
271				p.atLineStart = false
272			}
273			i := bytes.IndexAny(b, "\r\n")
274			var chunk []byte
275			if i < 0 {
276				chunk = b
277			} else {
278				chunk = b[:i+1]
279				p.atLineStart = true
280			}
281			n, err := p.w.Write(chunk)
282			consumed += n
283			if err != nil {
284				return consumed, fmt.Errorf("write chunk: %w", err)
285			}
286			b = b[len(chunk):]
287		}
288		return consumed, nil
289	}
