704	func subdivideCheckpoints(chain []plumbing.Hash, current plumbing.Hash, remaining []plumbing.Hash) []plumbing.Hash {
705		chainIdx := make(map[plumbing.Hash]int, len(chain))
706		for i, h := range chain {
707			chainIdx[h] = i
708		}
709		curIdx, ok := chainIdx[current]
710		if !ok && !current.IsZero() {
711			return remaining
712		}
713		if current.IsZero() {
714			curIdx = -1
715		}
716	
717		expanded := make([]plumbing.Hash, 0, len(remaining)*2)
718		prev := curIdx
719		for _, cp := range remaining {
720			cpIdx, ok := chainIdx[cp]
721			if !ok {
722				expanded = append(expanded, cp)
723				continue
724			}
725			gap := cpIdx - prev
726			if gap > 1 {
727				midIdx := prev + gap/2
728				expanded = append(expanded, chain[midIdx])
729			}
730			expanded = append(expanded, cp)
731			prev = cpIdx
732		}
733		return expanded
